-- Rev-N-Rip Garage Bay V1 Supabase schema
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, username text unique not null, display_name text, avatar_url text, garage_rank text default 'Rookie Ripper', completed_deals integer default 0, created_at timestamptz default now());
create table if not exists public.garage_rooms (id uuid primary key default gen_random_uuid(), title text not null default 'New Garage Bay', deal_type text not null default 'Cash + Trade', status text not null default 'draft_bay', created_by uuid references auth.users(id) on delete cascade, invited_user uuid references auth.users(id) on delete set null, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.garage_room_participants (room_id uuid references public.garage_rooms(id) on delete cascade, user_id uuid references auth.users(id) on delete cascade, role text not null check (role in ('creator','invited','admin')), locked boolean default false, locked_at timestamptz, primary key (room_id,user_id));
create table if not exists public.garage_offers (id uuid primary key default gen_random_uuid(), room_id uuid references public.garage_rooms(id) on delete cascade, user_id uuid references auth.users(id) on delete cascade, offer_type text not null default 'item', item_name text, cash_amount numeric default 0, estimated_value numeric default 0, condition_notes text, proof_notes text, created_at timestamptz default now());
create table if not exists public.garage_room_events (id uuid primary key default gen_random_uuid(), room_id uuid references public.garage_rooms(id) on delete cascade, user_id uuid references auth.users(id) on delete set null, event_type text not null, event_note text, created_at timestamptz default now());
alter table public.profiles enable row level security; alter table public.garage_rooms enable row level security; alter table public.garage_room_participants enable row level security; alter table public.garage_offers enable row level security; alter table public.garage_room_events enable row level security;
create policy "profiles viewable by authenticated" on public.profiles for select to authenticated using (true);
create policy "users update own profile" on public.profiles for update to authenticated using (auth.uid()=id) with check (auth.uid()=id);
create policy "participants view rooms" on public.garage_rooms for select to authenticated using (exists (select 1 from public.garage_room_participants p where p.room_id=garage_rooms.id and p.user_id=auth.uid()));
create policy "users create rooms" on public.garage_rooms for insert to authenticated with check (created_by=auth.uid());
create policy "participants update rooms" on public.garage_rooms for update to authenticated using (exists (select 1 from public.garage_room_participants p where p.room_id=garage_rooms.id and p.user_id=auth.uid()));
create policy "participants view participants" on public.garage_room_participants for select to authenticated using (exists (select 1 from public.garage_room_participants p where p.room_id=garage_room_participants.room_id and p.user_id=auth.uid()));
create policy "room creator adds participants" on public.garage_room_participants for insert to authenticated with check (exists (select 1 from public.garage_rooms r where r.id=garage_room_participants.room_id and r.created_by=auth.uid()) or user_id=auth.uid());
create policy "participants update own lock" on public.garage_room_participants for update to authenticated using (user_id=auth.uid()) with check (user_id=auth.uid());
create policy "participants view offers" on public.garage_offers for select to authenticated using (exists (select 1 from public.garage_room_participants p where p.room_id=garage_offers.room_id and p.user_id=auth.uid()));
create policy "participants add own offers" on public.garage_offers for insert to authenticated with check (user_id=auth.uid() and exists (select 1 from public.garage_room_participants p where p.room_id=garage_offers.room_id and p.user_id=auth.uid()));
create policy "users update own offers" on public.garage_offers for update to authenticated using (user_id=auth.uid()) with check (user_id=auth.uid());
create policy "users delete own offers" on public.garage_offers for delete to authenticated using (user_id=auth.uid());
create policy "participants view events" on public.garage_room_events for select to authenticated using (exists (select 1 from public.garage_room_participants p where p.room_id=garage_room_events.room_id and p.user_id=auth.uid()));
create policy "participants add events" on public.garage_room_events for insert to authenticated with check (user_id=auth.uid() and exists (select 1 from public.garage_room_participants p where p.room_id=garage_room_events.room_id and p.user_id=auth.uid()));
